#include<bits/stdc++.h>
using namespace std;
int a[1600010],stk[1600010],top;
int fa[1600010][25],lg[1600010],p[1600010],d[1600010];
int n,m;
vector<int> mp[1600010],mp1[1600010];
int tot;
bool vis[1600010];
int dfn[1600010],dis[1600010],low[1600010],dfncnt;
void tarjan(int x,int fa)
{
    dfn[x]=low[x]=++dfncnt;
    stk[++top]=x;
    vis[x]=true;
    for(int v:mp[x])if(v!=fa&&dfn[v]<=dfn[x])
    {
        if(!dfn[v])
        {
            tarjan(v,x);
            low[x]=min(low[x],low[v]);
        }
        else if(vis[v])
        {
            low[x]=min(low[x],dfn[v]);
            continue;
        }
        if(low[v]==dfn[x])
        {
            tot++;
            mp1[x].push_back(tot);
            while(stk[top]!=v)
            {
                vis[stk[top]]=false;
                mp1[tot].push_back(stk[top]);
                top--;
            }
            vis[v]=false;
            mp1[tot].push_back(v);
            top--;
        }
        else if(low[v]>dfn[x])
        {
            mp1[x].push_back(v);
            top--;
            vis[v]=false;
        }
    }
}
void dfs(int x,int f=0)
{
    dfn[x]=++dfncnt;
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp1[x])
    {
        if(i!=f)
        {
            dis[i]=dis[x]+(i<=n);
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int dist(int x,int y)
{
    return dis[x]+dis[y]-2*dis[lca(x,y)];
}
bool cmp(int x,int y)
{
    return dfn[x]<dfn[y];
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d%d",&n,&m);
        tot=n;
        for(int i=0;i<=m*4;i++)
        {
            lg[i]=__lg(i);
            mp[i].clear();
            mp1[i].clear();
            dfn[i]=0;
            stk[i]=0;
            vis[i]=false;
            d[i]=dis[i]=0;
            low[i]=dfn[i]=0;
            for(int j=0;j<=23;j++)
            {
                fa[i][j]=0;
            }
        }
        dfncnt=0;
        top=0;
        for(int i=1;i<=m;i++)
        {
            int u,v;
            scanf("%d%d",&u,&v);
            mp[u].push_back(v);
            mp[v].push_back(u);
        }
        tarjan(1,-1);
        dfncnt=0;
        d[1]=dis[1]=0;
        dfs(1);
        int q;
        scanf("%d",&q);
        while(q--)
        {
            int c;
            scanf("%d",&c);
            for(int i=1;i<=c;i++)
            {
                scanf("%d",&p[i]);
            }
            sort(p+1,p+1+c,cmp);
            int sum=0;
            p[c+1]=p[1];
            for(int i=1;i<=c;i++)
            {
                sum+=dist(p[i],p[i+1]);
            }
            printf("%d\n",sum/2-c+(lca(p[1],p[c])<=n));
        }
    }
    return 0;
}
